from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about an athlete into a fluent, combined sentence."""
    if not triples:
        return ""

    # organise triples by subject for easy lookup
    subj_map: dict[str, list[tuple[str, str]]] = {}
    for t in triples:
        subj_map.setdefault(t.subject, []).append((t.predicate, t.object))

    # helper to render a single (subject, predicate, object) with possible
    # augmentation using information from other triples
    def render(s: str, p: str, o: str) -> str:
        """Render a single triple, adding a concise relative clause when the object
        itself has useful predicates (e.g., a club’s city, manager, chairman)."""
        # ----- basic phrase construction -----
        if p == "birthDate":
            base = f"{s} was born on {o}"
        elif p == "birthYear":
            base = f"{s} was born in {o}"
        elif p == "birthPlace":
            base = f"{s} was born in {o}"
        elif p == "height":
            base = f"{s} is {o} meters tall"
        elif p == "weight":
            base = f"{s} weighs {o}"
        elif p == "position":
            base = f"{s} plays as a {o}"
        elif p in ("club", "currentclub"):
            base = f"{s} plays for {o}"
        elif p == "formerTeam":
            base = f"{s} formerly played for {o}"
        elif p == "league":
            base = f"{s} competes in the {o}"
        elif p == "manager":
            base = f"{s} is managed by {o}"
        elif p == "coach":
            base = f"{s} is coached by {o}"
        elif p == "draftYear":
            base = f"{s} was drafted in {o}"
        elif p == "draftRound":
            base = f"{s} was selected in round {o}"
        elif p == "draftPick":
            base = f"{s} was the {o}th pick"
        elif p == "playerNumber":
            base = f"{s} wears number {o}"
        elif p == "currentteam":
            base = f"{s} currently plays for {o}"
        elif p == "debutTeam":
            base = f"{s} debuted with {o}"
        elif p == "leader":
            base = f"{o} is the leader of {s}"
        elif p == "deathPlace":
            base = f"{s} died in {o}"
        elif p == "isPartOf":
            base = f"{s} is part of {o}"
        elif p == "country":
            base = f"{s} is in {o}"
        elif p == "ground":
            base = f"{s}'s ground is {o}"
        else:
            base = f"{s} {p} {o}"

        # ----- add relative clause when possible -----
        # map of predicate -> wording for relative clause
        rel_map = {
            "city": "based in",
            "ground": "located at",
            "manager": "managed by",
            "coach": "coached by",
            "chairman": "chaired by",
            "league": "competes in",
            "country": "in",
        }

        # If the object is also a subject elsewhere, try to attach the most
        # relevant secondary predicate as a relative clause.
        if o in subj_map:
            for rel_pred, wording in rel_map.items():
                for sp, so in subj_map[o]:
                    if sp == rel_pred:
                        # special handling for “city” to use “who is based in”
                        if rel_pred == "city":
                            base += f", who is {wording} {so}"
                        else:
                            base += f", which is {wording} {so}"
                        # attach only the first relevant clause
                        break
                else:
                    continue
                break

        return base

    # build phrases per subject, merging multiple predicates of the same subject
    phrases = []
    for s, pred_objs in subj_map.items():
        # if a subject has several predicates, join them with commas
        sub_phrases = [render(s, p, o) for p, o in pred_objs]
        if len(sub_phrases) == 1:
            phrases.append(sub_phrases[0])
        else:
            # combine with “and” for the last element
            combined = ", ".join(sub_phrases[:-1]) + f", and {sub_phrases[-1]}"
            phrases.append(combined)

    # finally join all subject‑level phrases into one sentence
    if len(phrases) == 1:
        return phrases[0] + "."
    else:
        return "; ".join(phrases) + "."

# EVOLVE-BLOCK-END

